.darma-loader-uiverse-pop-burst-action { display: inline-flex; align-items: center; justify-content: center; position: relative; }
.darma-loader-uiverse-pop-burst-action__container {
  --bg: #ff4500;
  --ink: #000000;
  --paper: #ffffff;
  --accent-1: #00d2ff;
  --accent-2: #ff00ff;
  --accent-3: #ffef00;
  --size: 110px;
  --half: 55px;
  --smooth-snap: cubic-bezier(0.85, 0, 0.15, 1);

margin: 0;
height: 100%;
width: 100%;
display: flex;
align-items: center;
justify-content: center;
/* background: var(--bg); */
overflow: hidden;
perspective: 1500px;
}

.darma-loader-uiverse-pop-burst-action__action-rays {
position: absolute;
width: 300vmax;
height: 300vmax;
/* background: repeating-conic-gradient(
from 0deg,
rgba(0,0,0,0.15) 0deg 10deg,
transparent 10deg 20deg
); */
/* animation: darma-loader-uiverse-pop-burst-action-raySpin 20s linear infinite; */
z-index: -1;
}

@keyframes darma-loader-uiverse-pop-burst-action-raySpin {
to {
transform: rotate(360deg);
}
}

.darma-loader-uiverse-pop-burst-action__container::after {
content: "";
position: absolute;
inset: 0;
background-image: radial-gradient(var(--ink) 1px, transparent 1px);
background-size: 15px 15px;
opacity: 0.1;
pointer-events: none;
}

.darma-loader-uiverse-pop-burst-action__stage {
position: relative;
width: var(--size);
height: var(--size);
transform-style: preserve-3d;
animation: darma-loader-uiverse-pop-burst-action-stageJump 4s var(--smooth-snap) infinite;
}

@keyframes darma-loader-uiverse-pop-burst-action-stageJump {
0%,
100% {
transform: scale(1) rotateX(-20deg) rotateY(0deg);
}
50% {
transform: scale(1.3) rotateX(160deg) rotateY(180deg);
}
}

.darma-loader-uiverse-pop-burst-action__cube {
position: absolute;
inset: 0;
transform-style: preserve-3d;
animation: darma-loader-uiverse-pop-burst-action-autoRotate 8s linear infinite;
}

@keyframes darma-loader-uiverse-pop-burst-action-autoRotate {
to {
transform: rotateY(360deg) rotateZ(360deg);
}
}

.darma-loader-uiverse-pop-burst-action__face {
position: absolute;
width: 100%;
height: 100%;
background: var(--paper);
border: 5px solid var(--ink);
box-sizing: border-box;
display: flex;
flex-direction: column;
align-items: center;
justify-content: center;
backface-visibility: visible;
overflow: hidden;
box-shadow: 12px 12px 0 var(--ink);
}

.darma-loader-uiverse-pop-burst-action__f-1 {
transform: rotateY(0deg) translateZ(var(--half));
background: var(--accent-1);
}
.darma-loader-uiverse-pop-burst-action__f-2 {
transform: rotateY(180deg) translateZ(var(--half));
background: var(--accent-2);
}
.darma-loader-uiverse-pop-burst-action__f-3 {
transform: rotateY(90deg) translateZ(var(--half));
background: var(--accent-3);
}
.darma-loader-uiverse-pop-burst-action__f-4 {
transform: rotateY(-90deg) translateZ(var(--half));
background: var(--paper);
}
.darma-loader-uiverse-pop-burst-action__f-5 {
transform: rotateX(90deg) translateZ(var(--half));
background: #ff5252;
}
.darma-loader-uiverse-pop-burst-action__f-6 {
transform: rotateX(-90deg) translateZ(var(--half));
background: #00e676;
}

.darma-loader-uiverse-pop-burst-action__face::before {
content: "";
position: absolute;
width: 150%;
height: 20px;
background: var(--ink);
transform: rotate(-45deg) translateY(-40px);
opacity: 0.2;
}

.darma-loader-uiverse-pop-burst-action__panel-num {
font-family: "Arial Black", sans-serif;
font-size: 40px;
color: var(--ink);
line-height: 1;
margin: 0;
transform: skew(-10deg);
z-index: 2;
}

.darma-loader-uiverse-pop-burst-action__panel-label {
font-family: "Arial Black", sans-serif;
font-size: 12px;
background: var(--ink);
color: #fff;
padding: 2px 8px;
margin-top: 5px;
text-transform: uppercase;
z-index: 2;
}

.darma-loader-uiverse-pop-burst-action__pop-burst {
position: absolute;
width: 100%;
height: 100%;
pointer-events: none;
display: flex;
align-items: center;
justify-content: center;
z-index: 10;
}

.darma-loader-uiverse-pop-burst-action__word {
position: absolute;
font-family: "Arial Black", sans-serif;
font-size: 60px;
color: var(--paper);
-webkit-text-stroke: 3px var(--ink);
text-shadow: 8px 8px 0 var(--accent-2);
opacity: 0;
animation: darma-loader-uiverse-pop-burst-action-comicFlash 4s var(--smooth-snap) infinite;
}

@keyframes darma-loader-uiverse-pop-burst-action-comicFlash {
0%,
48%,
52%,
100% {
opacity: 0;
transform: scale(0.5) rotate(-20deg);
}
50% {
opacity: 1;
transform: scale(1.4) rotate(5deg);
}
}

.darma-loader-uiverse-pop-burst-action__shadow-floor {
position: absolute;
bottom: -100px;
width: 150px;
height: 40px;
background: rgba(0, 0, 0, 0.3);
border-radius: 50%;
filter: blur(10px);
animation: darma-loader-uiverse-pop-burst-action-shadowPulse 4s var(--smooth-snap) infinite;
}

@keyframes darma-loader-uiverse-pop-burst-action-shadowPulse {
0%,
100% {
transform: scale(1);
opacity: 0.5;
}
50% {
transform: scale(0.4);
opacity: 0.1;
}
}

